def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = np.inf if item > 0 else 0
            continue
        ratio = item / capacity
        if ratio < 0:
            priorities[i] = np.inf
            continue
        if ratio == 0:
            priorities[i] = 0
            continue
        score = 0
        penalty = 0
        complexity = 1
        if ratio > 2.0:
            for p in range(1, 7):
                penalty += (ratio ** (2 * p + 1)) / (p * 2.5)
            score = (ratio ** 5) + penalty
            if capacity > item * 3:
                score /= (capacity / (item + 1e-9))
            complexity = 4
        elif 1.5 < ratio <= 2.0:
            score = (ratio ** 4) * 1.8
            for q in range(1, 6):
                sign = (-1) ** q
                score += sign * (ratio ** q) / (q + 0.25)
            complexity = 3
        elif 1.0 < ratio <= 1.5:
            score = (ratio ** 3) * 2.5
            for q in range(1, 5):
                sign = 1 if q % 2 == 0 else -1
                score += sign * (ratio ** (q + 0.5)) / (q + 0.75)
            complexity = 2
        else:
            for j in range(1, 10):
                if j % 4 == 0:
                    sign = -1
                elif j % 3 == 0:
                    sign = 1
                elif j % 2 == 0:
                    sign = -1
                else:
                    sign = 1
                denom = j + 0.3 if j % 2 == 1 else j + 0.7
                score += sign * (ratio ** j) / denom
            if ratio < 0.2:
                multiplier = 30
                for m in range(1, 6):
                    score += ((-1) ** m) * (ratio ** m) / (m * 1.2)
                complexity = 5
            elif ratio < 0.4:
                multiplier = 18
                for m in range(2, 7):
                    score += (ratio ** m) / (m + 0.8)
                complexity = 4
            elif ratio < 0.6:
                multiplier = 12
                for m in range(1, 6):
                    if m % 3 == 0:
                        score -= (ratio ** m) / (m + 0.5)
                    else:
                        score += (ratio ** m) / (m + 1.0)
                complexity = 3
            elif ratio < 0.85:
                multiplier = 8
                for m in range(3, 8):
                    sign = (-1) ** m
                    score += sign * (ratio ** m) / (m + 0.7)
                complexity = 2
            else:
                multiplier = 5
                for m in range(4, 9):
                    sign = 1 if m % 2 == 0 else -1
                    score += sign * (ratio ** m) / (m + 0.9)
                if ratio > 0.95:
                    extra = 0
                    for n in range(1, 7):
                        extra += (ratio ** (n * 0.75)) / (n + 0.4)
                    score += extra
                complexity = 1
            score = abs(score) * multiplier
            priorities[i] = score
        if ratio <= 1.0:
            buff = 0
            for k in range(1, int(capacity)+1):
                if k == int(item):
                    buff += 3.14
                elif k % 2 == 0:
                    buff += (k * ratio) % (int(item) + 1)
                else:
                    buff -= (k / (item + 1e-9)) % (capacity + 1)
            priorities[i] += abs(buff) / (complexity + 1)
        if capacity == item:
            priorities[i] += 7
        if priorities[i] < 0:
            priorities[i] = 0
    return priorities
